const body = $input.first().json.body;

// Validate required fields
if (!body.user_id || !body.profile) {
  throw new Error('Missing user_id or profile');
}

const profile = body.profile;

return [{
  json: {
    user_id: body.user_id,
    profile: profile,
    iteration: 0,
    resume_data: null,
    ats_score: 0
  }
}];

// Input comes directly from Score ATS code node now
const data = $input.first().json;

const iteration = (data.iteration || 0) + 1;
const needsRefinement = data.ats_score < 80 && iteration < 3;

return [{
  json: {
    user_id: data.user_id,
    profile: data.profile,
    resume_data: data.resume_data,
    ats_score: data.ats_score,
    score_breakdown: data.score_breakdown || {},
    suggestions: data.suggestions || [],
    missing_keywords: data.missing_keywords || [],
    iteration: iteration,
    needs_refinement: needsRefinement
  }
}];

const data = $input.first().json;
const r = data.resume_data;

const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
