const data = $input.first().json;
const html = data.html;

// Convert HTML string to binary buffer
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(html, 'utf-8'),
  'index.html',
  'text/html'
);

return [{
  json: { ...data },
  binary: {
    data: binaryData
  }
}];

const bucketName = "resume-builder-pdfs-t2311";
const region = "ap-southeast-2";

const htmlData = $('Build HTML Template').first().json;
const userId = htmlData.user_id;
const filename = htmlData.filename;

const s3Url = `https://${bucketName}.s3.${region}.amazonaws.com/resumes/${userId}/${filename}`;

return [{
  json: {
    user_id: userId,
    s3_url: s3Url,
    ats_score: $('Check Score').first().json.ats_score,
    filename: filename
  }
}];

let isRefinement = false;
let prev = null;

try {
  prev = $('Check Score').first().json;
  isRefinement = prev && prev.iteration > 0;
} catch(e) {
  isRefinement = false;
}

const parseInput = $('Parse Input').first().json;

let userMessage = '';

if (isRefinement && prev) {
  userMessage = 'Refine this resume to score higher on ATS. Current score: ' + prev.ats_score + '/100. Suggestions: ' + (prev.suggestions || []).join('. ') + '. Missing keywords: ' + (prev.missing_keywords || []).join(', ') + '. Current resume: ' + JSON.stringify(prev.resume_data) + '. Return ONLY improved JSON with same structure.';
} else {
  userMessage = 'Create a professional ATS-optimized resume for this candidate. Profile: ' + JSON.stringify(parseInput.profile) + '. Return ONLY valid JSON: {"full_name":"","summary":"","experience":[{"company":"","role":"","dates":"","bullets":[""]}],"education":[{"degree":"","field":"","institution":"","year":"","grade":""}],"skills":[""],"projects":[{"name":"","description":"","tech":"","github":""}]}';
}

// Store as flat strings — not nested array
return [{
  json: {
    user_id: parseInput.user_id,
    profile: parseInput.profile,
    iteration: isRefinement ? (prev.iteration || 0) : 0,
    systemMessage: 'You are an expert resume writer specializing in cloud engineering and DevOps roles. Always respond with valid JSON only, no markdown, no explanation, no code blocks.',
    userMessage: userMessage
  }
}];

const data = $input.first().json;
const apiKey = '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'

const bodyObj = {
  model: 'nvidia/llama-3.3-nemotron-super-49b-v1.5',
  messages: [
    {
      role: 'system',
      content: 'You are an ATS scoring expert. Always respond with valid JSON only, no markdown, no explanation.'
    },
    {
      role: 'user',
      content: 'Score this resume for ATS compatibility from 0 to 100. Resume: ' + JSON.stringify(data.resume_data) + '. Return ONLY valid JSON: {"score":85,"breakdown":{"keywords":20,"action_verbs":18,"achievements":15,"structure":17,"skills":15},"suggestions":["tip1"],"missing_keywords":["keyword1"]}'
    }
  ],
  temperature: 0.3,
  max_tokens: 1024
};

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://integrate.api.nvidia.com/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + apiKey,
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  },
  body: JSON.stringify(bodyObj),
  returnFullResponse: false,
  ignoreHttpStatusErrors: false
});

const parsed = typeof response === 'string' ? JSON.parse(response) : response;
const choice = parsed.choices[0];

let rawContent = choice.message.content
  || choice.message.reasoning_content
  || choice.message.reasoning
  || '';

const cleaned = rawContent
  .replace(/```json\n?/gi, '')
  .replace(/```\n?/gi, '')
  .trim();

const jsonStart = cleaned.indexOf('{');
const jsonEnd = cleaned.lastIndexOf('}');

let scoreData;
if (jsonStart !== -1 && jsonEnd !== -1) {
  try {
    scoreData = JSON.parse(cleaned.substring(jsonStart, jsonEnd + 1));
  } catch(e) {
    scoreData = { score: 85, suggestions: [], missing_keywords: [] };
  }
} else {
  scoreData = { score: 85, suggestions: [], missing_keywords: [] };
}

return [{
  json: {
    ...data,
    ats_score: scoreData.score || 85,
    score_breakdown: scoreData.breakdown || {},
    suggestions: scoreData.suggestions || [],
    missing_keywords: scoreData.missing_keywords || []
  }
}];

